import java.io.*;
import org.apache.commons.text.StringEscapeUtils; // Using Apache Commons Text library for HTML escaping

public class XSSSecureCode {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

            System.out.println("Enter your name:");
            String userInput = reader.readLine();

            // Escaping user input to prevent XSS attacks
            String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);

            System.out.println("<p>Welcome, " + safeUserInput + "!</p>");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

